import React from "react";
import { Outlet, Link } from "react-router-dom";

const DashboardLayout = () => {
  const user = localStorage.getItem("loggedInUser") || "User";

  return (
    <div style={{ display: "flex" }}>

      {/* LEFT SIDEBAR */}
      <div className="sidebar">
      </div>

      {/* MAIN CONTENT */}
      <div className="main">
        <h1>Welcome, {user}</h1>
        
        <div style={{ textAlign: "center", marginTop: "30px" }}>
          <h2>Vendor Panel</h2>
          <div style={{ marginTop: "30px", display: "flex", flexDirection: "column", gap: "15px", alignItems: "center" }}>
            <Link to="/dashboard" style={{ padding: "10px 20px", backgroundColor: "#007bff", color: "white", textDecoration: "none", borderRadius: "5px", display: "inline-block", minWidth: "150px" }}>Dashboard</Link>
            <Link to="/dashboard/profit" style={{ padding: "10px 20px", backgroundColor: "#28a745", color: "white", textDecoration: "none", borderRadius: "5px", display: "inline-block", minWidth: "150px" }}>Profit</Link>
            <Link to="/dashboard/loss" style={{ padding: "10px 20px", backgroundColor: "#dc3545", color: "white", textDecoration: "none", borderRadius: "5px", display: "inline-block", minWidth: "150px" }}>Loss</Link>
            <Link to="/dashboard/expense" style={{ padding: "10px 20px", backgroundColor: "#ffc107", color: "black", textDecoration: "none", borderRadius: "5px", display: "inline-block", minWidth: "150px" }}>Expense</Link>
            <Link to="/dashboard/analytics" style={{ padding: "10px 20px", backgroundColor: "#17a2b8", color: "white", textDecoration: "none", borderRadius: "5px", display: "inline-block", minWidth: "150px" }}>Analytics</Link>
            <Link to="/dashboard/profile" style={{ padding: "10px 20px", backgroundColor: "#6c757d", color: "white", textDecoration: "none", borderRadius: "5px", display: "inline-block", minWidth: "150px" }}>Profile</Link>
          </div>
        </div>
        
        <Outlet />
      </div>

    </div>
  );
};

export default DashboardLayout;
